using System;
using System.Collections.Generic;

namespace CardGame
{
    /// <summary>
    /// 回合管理 — 驱动游戏主流程。
    /// <para>流程：StartTurn → CheckBoard → Draw → (等待出牌) → TryPlay → EndTurn → 下一位</para>
    /// <para>GameManager 在系统层按序调用各阶段方法，并在 Draw 与 TryPlay 之间处理玩家输入/CPU决策。</para>
    /// </summary>
    public class TurnManager
    {
        private readonly int[] _playerOrder;
        private int _currentIndex;

        /// <summary>当前回合玩家 ID。</summary>
        public int CurrentPlayerId => _playerOrder[_currentIndex];

        /// <summary>当前是第几轮（从 0 开始，每完整循环一轮 +1）。</summary>
        public int Round { get; private set; }

        // ── 事件（供 View 层监听）──────────────────────────────

        /// <summary>回合开始 (playerId)。</summary>
        public event Action<int> OnTurnStart;

        /// <summary>场地检查完成 (playerId)。</summary>
        public event Action<int> OnCheckBoardComplete;

        /// <summary>玩家摸牌 (playerId, card)。card 为 null 表示牌堆已空。</summary>
        public event Action<int, CardBase> OnCardDrawn;

        /// <summary>卡牌被打出到场地 (playerId, card, targetBoardId)。</summary>
        public event Action<int, CardBase, int> OnCardPlayed;

        /// <summary>卡牌效果结算完成 (playerId, card)。</summary>
        public event Action<int, CardBase> OnEffectResolved;

        /// <summary>出牌完整完成 (playerId, card, targetBoardId, effectTarget)。在效果结算和胜负检查之后触发。</summary>
        public event Action<int, CardBase, int, PlayTarget> OnPlayCompleted;

        /// <summary>回合结束 (playerId)。</summary>
        public event Action<int> OnTurnEnd;

        /// <summary>游戏结束，有玩家获胜 (winnerId)。</summary>
        public event Action<int> OnGameWon;

        // ── 生命周期 ──────────────────────────────────────────

        /// <param name="playerOrder">出牌顺序的玩家 ID 数组，首个为起始玩家。</param>
        public TurnManager(int[] playerOrder)
        {
            _playerOrder = playerOrder ?? throw new ArgumentNullException(nameof(playerOrder));
            _currentIndex = 0;
            Round = 0;
        }

        /// <summary>
        /// 初始化游戏：构建牌堆、洗牌、初始化场地、每人发 1 张手牌。
        /// </summary>
        /// <param name="context">游戏上下文。</param>
        /// <param name="copiesPerCard">每种牌的份数（默认 5 → 35 张）。</param>
        public void StartGame(IGameContext context, int copiesPerCard = 5)
        {
            // 构建牌堆
            var cards = CardFactory.CreateDeck(copiesPerCard);
            context.Deck.BuildDeck(cards);
            context.Deck.Shuffle();

            // 初始化场地
            context.Board.ClearAll();
            foreach (var player in context.Players)
                context.Board.InitPlayer(player.Id);

            // 重置玩家状态
            foreach (var player in context.Players)
            {
                player.Hand.Clear();
                player.Score = 0;
                player.IsImmune = false;
                player.CanPlay = true;
            }

            // 每人发 1 张手牌
            foreach (var player in context.Players)
            {
                var card = context.Deck.DrawCard();
                if (card != null)
                    player.Hand.Add(card);
            }

            _currentIndex = 0;
            Round = 0;
        }

        // ── 回合阶段 ──────────────────────────────────────────

        /// <summary>
        /// 阶段 1：回合开始 — 重置当前玩家的免疫标记。
        /// </summary>
        public void StartTurn(IGameContext context)
        {
            int playerId = CurrentPlayerId;
            var player = context.GetPlayer(playerId);
            if (player != null)
                player.IsImmune = false;

            context.CurrentPlayerId = playerId;
            OnTurnStart?.Invoke(playerId);
        }

        /// <summary>
        /// 阶段 2：检查场地 — 结算所有在场效果（Coffin 禁止出牌等）。
        /// </summary>
        public void CheckBoard(IGameContext context)
        {
            context.Board.CheckAllBoards(context);
            OnCheckBoardComplete?.Invoke(CurrentPlayerId);
        }

        /// <summary>
        /// 阶段 3：摸牌 — 当前玩家从牌堆顶摸 1 张。
        /// <para>若 CanPlay 为 false（Coffin 在场）或牌堆已空，则不摸牌。</para>
        /// </summary>
        /// <returns>摸到的卡牌；未摸到返回 null。</returns>
        public CardBase Draw(IGameContext context)
        {
            int playerId = CurrentPlayerId;
            var player = context.GetPlayer(playerId);
            if (player == null || !player.CanPlay)
                return null;

            var card = context.Deck.DrawCard();
            if (card != null)
                player.Hand.Add(card);

            OnCardDrawn?.Invoke(playerId, card);
            return card;
        }

        /// <summary>
        /// 阶段 4：出牌 — 验证并执行出牌动作。
        /// <para>包括：从手牌移除 → 放入目标场地 → 触发卡牌效果 → 检查胜负。</para>
        /// </summary>
        /// <param name="context">游戏上下文。</param>
        /// <param name="action">出牌动作。</param>
        /// <returns>true 表示出牌成功。</returns>
        public bool TryPlay(IGameContext context, PlayAction action)
        {
            if (!ValidatePlay(context, action, out string error))
                return false;

            int playerId = CurrentPlayerId;
            var player = context.GetPlayer(playerId);

            // 从手牌移除
            player.Hand.Remove(action.Card);

            // 放入目标场地（GoesToBoardAfterPlay = false 的牌不进场地）
            if (action.Card.GoesToBoardAfterPlay)
                context.Board.PlayCard(action.TargetBoardId, action.Card);

            OnCardPlayed?.Invoke(playerId, action.Card, action.TargetBoardId);

            // 触发卡牌效果
            if (!action.Card.EffectsSuppressed)
                action.Card.OnPlay(context, playerId, action.EffectTarget);

            OnEffectResolved?.Invoke(playerId, action.Card);

            // 检查胜负
            int winnerId = WinChecker.CheckWin(context);
            if (winnerId >= 0)
            {
                OnPlayCompleted?.Invoke(playerId, action.Card, action.TargetBoardId, action.EffectTarget);
                OnGameWon?.Invoke(winnerId);
                return true;
            }

            OnPlayCompleted?.Invoke(playerId, action.Card, action.TargetBoardId, action.EffectTarget);
            return true;
        }

        /// <summary>
        /// 阶段 5：回合结束 — 推进到下一位玩家。
        /// </summary>
        public void EndTurn()
        {
            int playerId = CurrentPlayerId;
            OnTurnEnd?.Invoke(playerId);

            _currentIndex = (_currentIndex + 1) % _playerOrder.Length;
            if (_currentIndex == 0)
                Round++;
        }

        // ── 验证 & 辅助 ───────────────────────────────────────

        /// <summary>
        /// 验证出牌动作是否合法。
        /// </summary>
        public bool ValidatePlay(IGameContext context, PlayAction action, out string error)
        {
            error = null;
            int playerId = CurrentPlayerId;
            var player = context.GetPlayer(playerId);

            if (player == null)
            {
                error = "玩家不存在";
                return false;
            }

            if (!player.CanPlay)
            {
                error = "玩家无法出牌（棺材效果）";
                return false;
            }

            if (action?.Card == null)
            {
                error = "出牌动作为空";
                return false;
            }

            // 卡牌必须在手牌中
            if (!player.Hand.Contains(action.Card))
            {
                error = "该牌不在玩家手中";
                return false;
            }

            // Coffin 优先规则：手中有棺材时必须打出棺材
            if (MustPlayCoffin(context) && action.Card.Id != 8)
            {
                error = "手中有棺材，必须优先打出棺材";
                return false;
            }

            // 棺材只能打向自己场地
            if (action.Card.Id == 8 && action.TargetBoardId != playerId)
            {
                error = "棺材必须打进自己面前";
                return false;
            }

            // 目标场地不能有相同点数的牌（仅对进入场地的牌检查）
            if (action.Card.GoesToBoardAfterPlay &&
                context.Board.HasCardWithId(action.TargetBoardId, action.Card.Id))
            {
                error = "目标场地已存在相同点数的牌";
                return false;
            }

            return true;
        }

        /// <summary>
        /// 当前玩家是否必须打出棺材（手中有棺材且可以出牌）。
        /// </summary>
        public bool MustPlayCoffin(IGameContext context)
        {
            var player = context.GetPlayer(CurrentPlayerId);
            if (player == null || !player.CanPlay)
                return false;

            // 自己场地没有棺材时，手牌中的棺材必须优先打出
            if (context.Board.HasCardWithId(CurrentPlayerId, 8))
                return false; // 场上已有棺材 → CanPlay 已为 false，不会走到这里

            foreach (var card in player.Hand)
            {
                if (card.Id == 8)
                    return true;
            }
            return false;
        }

        /// <summary>
        /// 获取一张卡牌的合法放置目标（场地无同点数牌的玩家 ID 列表）。
        /// </summary>
        public List<int> GetValidTargets(IGameContext context, int cardId)
        {
            var targets = new List<int>();
            foreach (var player in context.Players)
            {
                if (!context.Board.HasCardWithId(player.Id, cardId))
                    targets.Add(player.Id);
            }
            return targets;
        }

        /// <summary>当前玩家是否可以出牌（CanPlay 且手牌非空）。</summary>
        public bool CanCurrentPlayerPlay(IGameContext context)
        {
            var player = context.GetPlayer(CurrentPlayerId);
            return player != null && player.CanPlay && player.Hand.Count > 0;
        }
    }
}

using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

namespace CardGame
{
    /// <summary>
    /// 单局对局管理器 — 实现 IGameContext，管理一局完整对局流程。
    /// <para>职责：初始化玩家/牌堆/CPU → 驱动回合流程 → 对局结束产出 MatchResult。</para>
    /// <para>由 SystemManager 在 Match 阶段启动。</para>
    /// </summary>
    public class GameManager : MonoBehaviour, IGameContext
    {
        [Header("对局配置")]
        [Tooltip("每种卡牌的份数（×7 = 总牌数）")]
        [SerializeField] private int _copiesPerCard = 5;

        [Tooltip("CPU 思考延迟（秒）")]
        [SerializeField] private float _cpuThinkDelay = 1.5f;

        [Tooltip("被锁定（棺材）时的跳过延迟（秒）")]
        [SerializeField] private float _skipDelay = 0.5f;

        // ── 核心组件 ──────────────────────────────────────────

        private DeckManager _deck = new DeckManager();
        private BoardManager _board = new BoardManager();
        private readonly List<PlayerData> _players = new List<PlayerData>();
        private TurnManager _turnManager;
        private readonly List<CPUBehavior> _cpuBehaviors = new List<CPUBehavior>();

        // ── IGameContext 属性 ─────────────────────────────────

        public DeckManager Deck => _deck;
        public BoardManager Board => _board;
        public IReadOnlyList<PlayerData> Players => _players.AsReadOnly();
        public int CurrentPlayerId { get; set; }
        public TurnManager TurnManager => _turnManager;

        // ── 对局状态 ──────────────────────────────────────────

        public enum MatchState
        {
            Inactive,
            Playing,
            WaitingForHumanInput,
            MatchOver,
        }

        public MatchState State { get; private set; } = MatchState.Inactive;
        public bool IsMatchActive => State == MatchState.Playing || State == MatchState.WaitingForHumanInput;

        private bool _waitingForHumanInput;
        private MatchResult _pendingResult;
        private Action<MatchResult> _onMatchComplete;

        // ── 外部组件引用 ──────────────────────────────────────

        [SerializeField] private InGameScenario _inGameScenario;
        private InGameEventMonitor _eventMonitor;

        // ── 生命周期 ──────────────────────────────────────────

        /// <summary>
        /// 开始一局对局。
        /// </summary>
        /// <param name="onComplete">对局完成回调，返回 MatchResult。</param>
        public void StartMatch(Action<MatchResult> onComplete = null)
        {
            _onMatchComplete = onComplete;

            // 创建玩家：1 人类 + 2 CPU
            _players.Clear();
            _players.Add(new PlayerData(0, "你", isCPU: false));
            _players.Add(new PlayerData(1, "瘦子", isCPU: true));
            _players.Add(new PlayerData(2, "胖子", isCPU: true));

            // 创建 CPU 行为
            _cpuBehaviors.Clear();
            for (int i = 0; i < CPUCharacteristics.DefaultConfigs.Length; i++)
            {
                _cpuBehaviors.Add(new CPUBehavior(CPUCharacteristics.DefaultConfigs[i]));
            }

            // 创建回合管理器
            _turnManager = new TurnManager(new int[] { 0, 1, 2 });
            _turnManager.OnGameWon += OnGameWon;

            // 初始化场地
            _board.ClearAll();
            foreach (var p in _players)
                _board.InitPlayer(p.Id);

            // 初始化事件监视器
            if (_inGameScenario != null)
            {
                _inGameScenario.ClearAll();
                _eventMonitor = new InGameEventMonitor(_turnManager, this, _inGameScenario);
                _eventMonitor.StartMonitoring();
            }

            // 开始游戏
            _turnManager.StartGame(this, _copiesPerCard);
            State = MatchState.Playing;

            StartCoroutine(ProcessTurns());
        }

        /// <summary>停止对局（强制结束）。</summary>
        public void StopMatch()
        {
            State = MatchState.MatchOver;
            _eventMonitor?.StopMonitoring();
            _waitingForHumanInput = false;
        }

        // ── 回合驱动（协程）──────────────────────────────────

        private IEnumerator ProcessTurns()
        {
            while (State == MatchState.Playing)
            {
                // 阶段 1 & 2：回合开始 + 检查场地
                _turnManager.StartTurn(this);
                _turnManager.CheckBoard(this);

                int playerId = _turnManager.CurrentPlayerId;
                var player = GetPlayer(playerId);

                // 被锁定（棺材）→ 跳过
                if (player == null || !player.CanPlay)
                {
                    yield return new WaitForSeconds(_skipDelay);
                    _turnManager.EndTurn();
                    continue;
                }

                // 阶段 3：摸牌
                _turnManager.Draw(this);
                yield return null; // 让摸牌事件被 View 层处理

                // 阶段 4：出牌
                if (player.IsCPU)
                {
                    yield return new WaitForSeconds(_cpuThinkDelay);

                    int cpuIdx = playerId - 1; // CPU 玩家 ID 从 1 开始
                    if (cpuIdx >= 0 && cpuIdx < _cpuBehaviors.Count)
                    {
                        var action = _cpuBehaviors[cpuIdx].Decide(this, playerId);
                        if (action != null)
                            _turnManager.TryPlay(this, action);
                    }

                    yield return null;
                    _turnManager.EndTurn();
                }
                else
                {
                    // 人类玩家：等待输入
                    State = MatchState.WaitingForHumanInput;
                    _waitingForHumanInput = true;
                    yield return new WaitUntil(() => !_waitingForHumanInput);
                    State = MatchState.Playing;
                    _turnManager.EndTurn();
                }
            }
        }

        // ── 人类玩家输入入口 ──────────────────────────────────

        /// <summary>
        /// 提交人类玩家的出牌动作（由 InputController 调用）。
        /// </summary>
        /// <returns>true 表示出牌成功。</returns>
        public bool SubmitHumanPlay(PlayAction action)
        {
            if (State != MatchState.WaitingForHumanInput)
                return false;

            int playerId = _turnManager.CurrentPlayerId;
            var player = GetPlayer(playerId);
            if (player == null || player.IsCPU)
                return false;

            if (_turnManager.TryPlay(this, action))
            {
                _waitingForHumanInput = false;
                return true;
            }
            return false;
        }

        /// <summary>当前是否轮到人类玩家出牌。</summary>
        public bool IsHumanTurn =>
            State == MatchState.WaitingForHumanInput &&
            GetPlayer(_turnManager?.CurrentPlayerId ?? -1)?.IsCPU == false;

        // ── 对局结束 ──────────────────────────────────────────

        private void OnGameWon(int winnerId)
        {
            State = MatchState.MatchOver;
            _eventMonitor?.StopMonitoring();

            var result = new MatchResult
            {
                WinnerId = winnerId,
                HumanPlayerId = 0,
                TotalRounds = _turnManager.Round,
            };
            foreach (var player in _players)
            {
                result.BoardPoints[player.Id] =
                    WinChecker.GetUniqueCardCount(this, player.Id);
            }

            _pendingResult = result;
            _waitingForHumanInput = false; // 释放等待
            _onMatchComplete?.Invoke(result);
        }

        // ── IGameContext 实现 ────────────────────────────────

        public PlayerData GetPlayer(int playerId)
        {
            foreach (var p in _players)
                if (p.Id == playerId) return p;
            return null;
        }

        public List<int> GetOpponentIds(int playerId)
        {
            var opponents = new List<int>();
            foreach (var p in _players)
                if (p.Id != playerId) opponents.Add(p.Id);
            return opponents;
        }

        public void SwapHands(int playerA, int playerB)
        {
            var pa = GetPlayer(playerA);
            var pb = GetPlayer(playerB);
            if (pa == null || pb == null) return;

            var temp = new List<CardBase>(pa.Hand);
            pa.Hand.Clear();
            pa.Hand.AddRange(pb.Hand);
            pb.Hand.Clear();
            pb.Hand.AddRange(temp);
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 2 幸运草：抽一张牌，将原手牌放回牌堆顶。
    /// <para>打出后不进入场地，而是回收至牌堆顶并抽取新牌。</para>
    /// </summary>
    public class Card02_Clover : CardBase
    {
        public Card02_Clover() : base(2, "幸运草", "抽一张牌，将原手牌放回牌堆顶") { }

        /// <summary>此牌打出后回收至牌堆顶，不进入场地。</summary>
        public override bool GoesToBoardAfterPlay => false;

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            var player = context.GetPlayer(playerId);
            // 抽一张牌到手牌
            var drawn = context.Deck.DrawCard();
            if (drawn != null)
                player.Hand.Add(drawn);
            // 将此牌（原手牌）放回牌堆顶
            context.Deck.PutOnTop(this);
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 3 船：将对手牌区的一张牌移回牌堆底。
    /// <para>需要目标：target.TargetPlayerId（对手）、target.TargetCardIndex（对手场地上的卡牌索引）。</para>
    /// </summary>
    public class Card03_Boat : CardBase
    {
        public Card03_Boat() : base(3, "船", "将对手牌区的一张牌移回牌堆底") { }

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            if (target?.TargetPlayerId == null || target.TargetCardIndex < 0) return;

            int targetId = target.TargetPlayerId.Value;
            var targetPlayer = context.GetPlayer(targetId);

            // 免疫检查
            if (targetPlayer != null && targetPlayer.IsImmune) return;

            var card = context.Board.RemoveCard(targetId, target.TargetCardIndex);
            if (card != null)
                context.Deck.PutOnBottom(card);
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 4 房子：免疫下一轮其他玩家对你的影响。
    /// <para>打出后置 IsImmune = true，由游戏流程在下一轮开始时重置为 false。</para>
    /// </summary>
    public class Card04_House : CardBase
    {
        public Card04_House() : base(4, "房子", "免疫下一轮其他玩家对你的影响") { }

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            var player = context.GetPlayer(playerId);
            if (player != null)
                player.IsImmune = true;
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 5 树：立刻打出牌堆最上面那张牌，不触发效果。
    /// <para>抽取牌堆顶牌放入自己场地，并设置 EffectsSuppressed = true 使其不触发任何效果。</para>
    /// </summary>
    public class Card05_Tree : CardBase
    {
        public Card05_Tree() : base(5, "树", "立刻打出牌堆最上面那张牌，不触发效果") { }

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            var topCard = context.Deck.DrawCard();
            if (topCard == null) return;

            // 不触发该牌的任何效果
            topCard.EffectsSuppressed = true;
            context.Board.PlayCard(playerId, topCard);
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 6 云：查看牌堆顶和牌堆底的牌，并可以将它们互换。
    /// <para>查看操作由 View 层处理；若 target.Choice == true 则执行交换。</para>
    /// </summary>
    public class Card06_Cloud : CardBase
    {
        public Card06_Cloud() : base(6, "云", "查看牌堆顶和牌堆底的牌，并可以将它们互换") { }

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            // 查看牌堆顶和底（实际展示由 View 层在调用前处理）
            // 若玩家/AI选择互换，执行交换
            if (target?.Choice == true)
            {
                context.Deck.SwapTopBottom();
            }
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 7 蛇：与对手互换手牌。
    /// <para>需要目标：target.TargetPlayerId（交换手牌的对手）。</para>
    /// </summary>
    public class Card07_Snake : CardBase
    {
        public Card07_Snake() : base(7, "蛇", "与对手互换手牌") { }

        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null)
        {
            if (target?.TargetPlayerId == null) return;

            int targetId = target.TargetPlayerId.Value;
            var targetPlayer = context.GetPlayer(targetId);

            // 免疫检查
            if (targetPlayer != null && targetPlayer.IsImmune) return;

            context.SwapHands(playerId, targetId);
        }
    }
}

namespace CardGame.Cards
{
    /// <summary>
    /// 8 棺材：必须优先打进自己面前；存在于自己场上时，无法再出牌。
    /// <para>正常进入自己场地；OnFieldCheck 时将玩家 CanPlay 置 false。</para>
    /// <para>BoardManager.CheckAllBoards 每轮先重置 CanPlay = true，再遍历卡牌，
    /// 若 Coffin 仍在场上则重新置 false，移除后自动恢复。</para>
    /// </summary>
    public class Card08_Coffin : CardBase
    {
        public Card08_Coffin() : base(8, "棺材", "必须优先打进自己面前；存在于自己场上时，无法再出牌") { }

        // 打出时无即时效果，棺材的效果通过 OnFieldCheck 持续生效
        public override void OnPlay(IGameContext context, int playerId, PlayTarget target = null) { }

        public override void OnFieldCheck(IGameContext context, int playerId)
        {
            var player = context.GetPlayer(playerId);
            if (player != null)
                player.CanPlay = false;
        }
    }
}
